import{_ as a,o as t,c as o,an as r}from"./chunks/framework.yajyPZtj.js";const u=JSON.parse('{"title":"Release notes","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes.md","filePath":"release-notes.md","lastUpdated":null}'),s={name:"release-notes.md"};function n(l,e,i,d,c,p){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="Release-notes" tabindex="-1">Release notes <a class="header-anchor" href="#Release-notes" aria-label="Permalink to &quot;Release notes {#Release-notes}&quot;">​</a></h1><p>ComposedDistributions.jl follows a hybrid changelog approach:</p><ul><li><p><strong>GitHub Releases</strong>: All releases (automatically generated by TagBot)</p></li><li><p><strong>NEWS.md</strong>: Major releases requiring detailed context (shown below)</p></li></ul><p>See <a href="https://github.com/EpiAware/ComposedDistributions.jl/releases" target="_blank" rel="noreferrer">GitHub Releases</a> for minor/patch release information.</p><h2 id="Unreleased" tabindex="-1">Unreleased <a class="header-anchor" href="#Unreleased" aria-label="Permalink to &quot;Unreleased {#Unreleased}&quot;">​</a></h2><ul><li>Added <code>uncertain</code> / <code>Uncertain</code>: leaf distributions whose parameters are themselves distributions, nestable to any depth. <code>rand</code> draws the marginal so uncertain leaves compose everywhere, and the rest of the univariate surface (scalar <code>logpdf</code>/<code>cdf</code>/..., the moments, including a composed tree&#39;s overall moment) delegates to the template&#39;s central values. <code>has_uncertain(tree)</code> flags a tree that still holds an uncertain leaf, for a scoring/fitting loop to guard against a forgotten collapse. Collapse an uncertain leaf to its concrete template by pinning the parameters with <code>update(tree, params)</code>. Build one with a concrete template (<code>uncertain(Gamma(2.0, 1.0); shape = LogNormal(...))</code>), a positional family form (<code>uncertain(Gamma, LogNormal(...), 1.0)</code>), or the keyword family form. <code>truncated(uncertain(...))</code> pushes inside the template (conditional per-draw semantics). <code>params_table</code> gained a <code>prior</code> column carrying an uncertain parameter&#39;s spec, which <code>build_priors</code> now uses ahead of its per-row default.</li></ul><p>This file tracks notes for major releases and significant milestones; GitHub Releases (auto-generated from merged PRs) cover every release in between.</p>',7)])])}const h=a(s,[["render",n]]);export{u as __pageData,h as default};
